#include <iostream>
#include <queue>

using namespace std;

class Node {
public:
    int value;
    Node* left;
    Node* right;

    Node(int value, Node* left = nullptr, Node* right = nullptr) : value(value), left(left), right(right) {}
};

class Solution {
public:
    bool findParent(Node* node, int parent[], int n, int i)
    {
        if (node == nullptr || i < 0 || i >= n)
            return false;
        if (node->value == i)
            return true;
        if (!findParent(node->left, parent, n, i))
            return false;
        if (!findParent(node->right, parent, n, i))
            return false;
        parent[i] = node->value;
        return true;
    }

    bool queryLCA(Node* root, int n, int q1, int q2)
    {
        int parent[n];
        for (int i = 0; i < n; ++i)
            parent[i] = -1;
        queue<Node*> q;
        q.push(root);
        while (!q.empty())
        {
            Node* node = q.front();
            q.pop();
            if (node != nullptr)
            {
                q.push(node->left);
                q.push(node->right);
                parent[node->value] = node->parent;
            }
        }
        if (parent[q1] != -1 && parent[q2] != -1 && parent[q1] == parent[q2])
            return true;
        return false;
    }
};

int main()
{
    Node* root = new Node(1);
    root->left = new Node(2);
    root->right = new Node(3);
    root->left->left = new Node(4);
    root->left->right = new Node(5);

    Solution solution;
    cout << solution.queryLCA(root, 6, 6, 2) << endl;
    return 0;
}
